#!/usr/bin/env python3
"""self-improving-claude/lint-before-commit
Enforces the CLAUDE.md convention: `pnpm lint` must pass before committing.
Runs lint on `git commit` and blocks the commit if it fails."""
import json
import re
import subprocess
import sys


def main():
    try:
        data = json.loads(sys.stdin.read())
    except Exception:
        sys.exit(0)

    if data.get("tool_name") != "Bash":
        sys.exit(0)

    cmd = (data.get("tool_input") or {}).get("command", "")
    if not re.search(r"\bgit\s+commit\b", cmd):
        sys.exit(0)

    try:
        proc = subprocess.run(
            ["pnpm", "lint"], capture_output=True, text=True, timeout=120
        )
    except Exception:
        # Don't block a commit if the linter itself can't be run.
        sys.exit(0)

    if proc.returncode != 0:
        tail = (proc.stdout + proc.stderr).strip().splitlines()[-20:]
        sys.stderr.write(
            "BLOCKING: `pnpm lint` failed — CLAUDE.md requires a clean lint before "
            "committing. Fix each error below, then re-run the commit. "
            "Do not bypass with --no-verify.\n" + "\n".join(tail) + "\n"
        )
        sys.exit(2)

    sys.exit(0)


main()

#!/usr/bin/env python3
"""self-improving-claude/block-env-reads

Blocks reads of .env secret files across Read, Grep, and Bash, while allowing
example/template files (.env.example, .env.sample, ...) that contain no secrets.
"""
import json
import re
import sys

# Suffixes that mark a template with no real secrets — safe to read.
ALLOW_SUFFIXES = (".example", ".sample", ".template", ".dist", ".defaults")


def is_env_secret(path):
    if not path:
        return False
    base = path.rsplit("/", 1)[-1]
    if not re.match(r"^\.env(\.|$)", base):
        return False
    return not base.endswith(ALLOW_SUFFIXES)


def main():
    try:
        data = json.load(sys.stdin)
    except Exception:
        sys.exit(0)

    tool = data.get("tool_name", "")
    tool_input = data.get("tool_input", {}) or {}

    targets = []
    if tool in ("Read", "Grep"):
        p = tool_input.get("file_path") or tool_input.get("path")
        if p:
            targets.append(p)
    elif tool == "Bash":
        cmd = tool_input.get("command", "") or ""
        targets.extend(re.findall(r"[^\s'\";|&><]*\.env[^\s'\";|&><]*", cmd))

    for t in targets:
        if is_env_secret(t):
            sys.stderr.write(
                "Blocked: '%s' is a .env secrets file and reading it could expose "
                "credentials. Use a .env.example template for variable names, or ask "
                "the user to share specific values directly if you genuinely need "
                "them.\n" % t
            )
            sys.exit(2)

    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, run ruff (format check + lint) and
feed any findings back to Claude immediately, so issues are fixed on the spot
instead of surfacing at a later manual `ruff check`."""
import json, shutil, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0

    path = (ev.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py"):
        return 0

    if shutil.which("ruff") is None:
        return 0  # ruff not installed; nothing to enforce

    problems = []
    for label, cmd in (
        ("ruff format --check", ["ruff", "format", "--check", path]),
        ("ruff check", ["ruff", "check", path]),
    ):
        try:
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=15)
        except Exception:
            continue
        if r.returncode != 0:
            out = (r.stdout + r.stderr).strip()
            problems.append(f"[{label}]\n{out}")

    if not problems:
        return 0

    print(f"REQUIRED FOLLOW-UP: ruff reported issues in {path}:", file=sys.stderr)
    for p in problems:
        print(p, file=sys.stderr)
    print(
        "Fix each, then re-run ruff. Do not stop until ruff passes. Do not ask.",
        file=sys.stderr,
    )
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json, sys, re, subprocess

EXPORT_DECL = re.compile(
    r'export\s+(?:default\s+)?(?:const|let|var|function|class|type|interface|enum)\s+([A-Za-z_$][\w$]*)')
EXPORT_BRACE = re.compile(r'export\s*\{([^}]*)\}')
STR_VAL = re.compile(r"""['\"`]([^'\"`\n]+)['\"`]""")


def exported_names(text):
    found = set(EXPORT_DECL.findall(text))
    for blob in EXPORT_BRACE.findall(text):
        for part in blob.split(','):
            name = part.strip().split(' as ')[0].strip()
            if name:
                found.add(name)
    return found


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name", "") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    root = ev.get("cwd") or "."
    pairs = []
    if "old_string" in inp:
        pairs.append((inp.get("old_string", ""), inp.get("new_string", "")))
    for e in inp.get("edits") or []:
        pairs.append((e.get("old_string", ""), e.get("new_string", "")))

    tokens = set()
    for old, new in pairs:
        old_ids = exported_names(old)
        tokens |= (old_ids - exported_names(new))   # renamed / removed export name
        if old_ids:                                 # export line touched -> also catch value change
            tokens |= (set(STR_VAL.findall(old)) - set(STR_VAL.findall(new)))
    tokens = {t for t in tokens if len(t) >= 3}
    if not tokens:
        return 0

    report = []
    for tok in sorted(tokens):
        try:
            out = subprocess.run(
                ["grep", "-rnw", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", "--exclude-dir=node_modules",
                 "--exclude-dir=.git", "--exclude-dir=dist", "--exclude-dir=build",
                 "-F", "-e", tok, root],
                capture_output=True, text=True, timeout=10).stdout
        except Exception:
            out = ""
        hits = [ln for ln in out.splitlines() if ln.strip()]
        if hits:
            report.append((tok, hits))
    if not report:
        return 0

    msg = ["BLOCKING: you changed an exported identifier or its constant value. "
           "REQUIRED FOLLOW-UP: the references below may now be broken. "
           "Fix each broken reference to match the change, then summarize. "
           "Do not stop until every reference is handled. Do not ask whether to proceed."]
    for tok, hits in report:
        msg.append("\n  '%s' -> %d reference(s):" % (tok, len(hits)))
        msg += ["    " + h for h in hits[:40]]
        if len(hits) > 40:
            msg.append("    ... and %d more" % (len(hits) - 40))
    sys.stderr.write("\n".join(msg) + "\n")
    return 2


if __name__ == "__main__":
    sys.exit(main())

import json, re, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name", "") != "Bash":
        return 0

    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "") or ""

    if not re.search(r"\bgit\s+push\b", cmd):
        return 0

    force = re.search(r"(?:^|\s)(?:--force(?:-with-lease)?|-f)(?:\s|=|$)", cmd)
    if not force:
        return 0

    if not re.search(r"\b(?:main|master)\b", cmd):
        return 0

    sys.stderr.write(
        "BLOCKING: force-pushing to main/master rewrites shared history and "
        "cannot be undone. Project policy requires a human to run this. "
        "Push to a feature branch and open a PR, or hand this command to a "
        "teammate to run manually.\n"
    )
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit calls that embed a hardcoded secret into source.

PreToolUse hook. Reads the tool payload, scans the text about to be written
for high-confidence secret shapes, and exits 2 (blocking) when one is found.
Project convention: secrets come from process.env, not source literals.
"""
import json
import re
import sys

PATTERNS = [
    ("OpenAI API key", r"sk-[A-Za-z0-9_-]{20,}"),
    ("AWS access key ID", r"AKIA[0-9A-Z]{16}"),
    ("GitHub token", r"gh[pousr]_[A-Za-z0-9]{36,}"),
    ("Google API key", r"AIza[0-9A-Za-z_-]{35}"),
    ("Slack token", r"xox[baprs]-[A-Za-z0-9-]{10,}"),
    ("Stripe secret key", r"sk_live_[A-Za-z0-9]{16,}"),
    ("Private key block", r"-----BEGIN (?:RSA |EC |OPENSSH |DSA |PGP )?PRIVATE KEY-----"),
]


def collect_text(tool, ti):
    if tool == "Write":
        return ti.get("content", "") or ""
    if tool == "Edit":
        return ti.get("new_string", "") or ""
    if tool == "MultiEdit":
        return "\n".join(
            (e.get("new_string", "") or "") for e in (ti.get("edits") or [])
        )
    return ""


def main():
    try:
        data = json.load(sys.stdin)
    except Exception:
        sys.exit(0)

    tool = data.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        sys.exit(0)

    ti = data.get("tool_input") or {}
    text = collect_text(tool, ti)
    if not isinstance(text, str) or not text:
        sys.exit(0)

    hits = sorted({label for label, pat in PATTERNS if re.search(pat, text)})
    if not hits:
        sys.exit(0)

    path = ti.get("file_path", "the target file")
    sys.stderr.write(
        "Blocked: this write embeds a hardcoded secret ("
        + ", ".join(hits)
        + ") into " + str(path) + ".\n"
        "Project convention (CLAUDE.md): secrets come from the environment. "
        "Read the value from process.env and add the variable name to "
        ".env.example, rather than placing the literal secret in source.\n"
    )
    sys.exit(2)


if __name__ == "__main__":
    main()

