#!/usr/bin/env python3
"""After editing a Python file, run the test suite and feed any failures back
to Claude so it must fix them before claiming the change is done."""
import json, os, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") not in ("Edit", "Write", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0

    proj = os.environ.get("CLAUDE_PROJECT_DIR") or "."
    try:
        r = subprocess.run(
            [sys.executable, "-m", "pytest", "-q"],
            cwd=proj, capture_output=True, text=True, timeout=120,
        )
    except Exception:
        return 0  # pytest missing or timed out -- don't block on tooling

    # 0 = all passed, 5 = no tests collected. Nothing to enforce either way.
    if r.returncode in (0, 5):
        return 0

    tail = "\n".join((r.stdout + r.stderr).splitlines()[-25:])
    print("REQUIRED FOLLOW-UP: pytest failed after your Python edit:", file=sys.stderr)
    print(tail, file=sys.stderr)
    print("Fix each failure, then re-run pytest. Do not stop until it passes. Do not ask.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())
